const html = items[0].json.data;

if (typeof html !== 'string' || html.length < 100) {
  throw new Error('Expected HTML string from HTTP Request. Check responseFormat=string');
}

// Hacker News markup (current-ish): <span class="titleline"><a href="...">Title</a></span>
// Regex-based parser (no external deps). If HN changes markup, update the regex.
const re = /<span class="titleline">\s*<a href="([^"]+)"[^>]*>([\s\S]*?)<\/a>/g;

const decode = (s) => s
  .replace(/&amp;/g, '&')
  .replace(/&quot;/g, '"')
  .replace(/&#x27;/g, "'")
  .replace(/&#39;/g, "'")
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

const rows = [];
let m;
while ((m = re.exec(html)) !== null) {
  const url = decode(m[1]);
  const title = decode(m[2].replace(/<[^>]+>/g, ''));
  if (!title) continue;
  rows.push({ title, url });
  if (rows.length >= 15) break;
}

if (rows.length === 0) {
  throw new Error('Parsed 0 items. Website markup likely changed; update regex in Code node.');
}

return [
  {
    json: {
      source: 'Hacker News front page (HTML scrape)',
      fetchedAt: new Date().toISOString(),
      items: rows
    }
  }
];
